// Per-item Code node. $json is the agent output for THIS item.
const raw = $json.output;
let out = {};
if (raw && typeof raw === 'object') {
  out = raw;
} else if (typeof raw === 'string') {
  const cleaned = raw.replace(/^\s*```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  try { out = JSON.parse(cleaned); } catch (e) { out = { matched: false, _parseError: String(e), _raw: raw.slice(0, 500) }; }
}

// Source Airtable row for THIS iteration
const src = $('Get Company by ID').first().json;

const matched = !!out.matched;
const parseNum = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(String(v).replace(/[^0-9.\-]/g, ''));
  return Number.isFinite(n) ? n : null;
};

const fields = {
  id: src.id,
  'Trigger': 'Done',
  'SF Sync Timestamp':       new Date().toISOString(),
  'SF Account ID':           out.account_id || null,
  'SF Account Ownership':    out.owner_name || null,
  'Industry':                out.industry || null,
  'Revenue Range':           out.annual_revenue ? String(out.annual_revenue) : null,
  'Employee Count':          parseNum(out.number_of_employees),
  'Stock Ticker':            out.ticker_symbol || null,
  'SF Has Open Opp':         matched && out.latest_opportunity_is_closed === false ? true : null,
  'SF Has Closed Won':       matched && out.latest_opportunity_is_won === true ? true : null,
  'SF Account Status Summary': matched
    ? `SF Account ${out.account_id} (${out.account_name}). Last modified ${out.last_modified_date || 'n/a'}. Latest opp: ${out.latest_opportunity_stage || 'none'} ${out.latest_opportunity_amount ? '$'+out.latest_opportunity_amount : ''}.`
    : (out._parseError ? `Agent parse error: ${out._parseError}` : 'No matching Salesforce Account found.')
};
for (const k of Object.keys(fields)) {
  if (fields[k] === null || fields[k] === undefined) delete fields[k];
}
return { json: fields };

// Read context from upstream nodes in this workflow
const company  = ($('Get Company by ID').first()?.json) || {};
const fieldsIn = company.fields || {};
const companyName = fieldsIn['Company Name'] || '';
const play       = fieldsIn['Play'] || '';

// Map node's output is in $json (we are immediately downstream of Update Company Record,
// which echoes the Airtable record; the mapped agent output lived in the Map node).
const mapped = ($('Map to Airtable Fields').first()?.json) || {};
const matched = !!mapped['SF Account ID'];

const recordsIn  = 1;            // one webhook invocation = one company in
const recordsOut = matched ? 1 : 0;

const eid = (typeof $execution !== 'undefined' && $execution && $execution.id)
  || (typeof $executionId !== 'undefined' ? $executionId : '');
const today  = new Date().toISOString().slice(0, 10);
const nowIso = new Date().toISOString();

return {
  json: {
    Name: `SF Enrichment - ${companyName || 'unknown'} - ${today}`,
    Status: 'Done',
    'Run Date': nowIso,
    Play: play || '',
    'Gate Version': 'sf-enrichment-v1',
    'Companies Evaluated': 1,
    'Records In': recordsIn,
    'Records Out': recordsOut,
    'Run Type': 'enrichment',
    'Run Mode': 'incremental',
    'Rules Version': 'sf-enrichment-v1',
    'Workflow ID': 'j2Zbn27q90g8yquT',
    'Execution ID': String(eid),
    Providers: ['salesforce', 'anthropic'],
    Companies: company.id ? [company.id] : [],
    Notes: matched
      ? `SF enrichment for ${companyName}. Matched SF Account ${mapped['SF Account ID']} (${mapped['SF Account Ownership'] || 'unknown owner'}). Wrote SF fields to Companies row.`
      : `SF enrichment for ${companyName}. No matching Salesforce Account found.`,
  }
};
